<?php
namespace Tests\Unit;
use App\Services\Trading\PortfolioApprovalService;
use Tests\TestCase;
class PortfolioApprovalServiceTest extends TestCase
{protected function svc():PortfolioApprovalService{return new PortfolioApprovalService();}protected function candidate($status='candidate_ready'):array{return ['schema_version'=>'trading_action_candidate_v1','status'=>$status,'candidate_id'=>'candidate-1','intent'=>'BUY'];}protected function risk($pr='evaluated_reference'):array{return ['action_specific_risk'=>['schema_version'=>'trading_action_risk_v1','status'=>'evaluated_reference'],'capital_risk'=>['schema_version'=>'trading_capital_risk_v1','status'=>'evaluated_reference'],'position_sizing'=>['schema_version'=>'trading_position_sizing_v1','status'=>'reference_sized'],'portfolio_risk'=>['schema_version'=>'trading_portfolio_risk_v1','status'=>$pr,'portfolio_id'=>'portfolio-1']];}protected function plan():array{return ['reference_plan'=>['schema_version'=>'trading_reference_trade_plan_v1','status'=>'materialized'],'execution_readiness'=>['schema_version'=>'trading_execution_readiness_v1','status'=>'reference_ready']];}protected function policy():array{return ['schema_version'=>'trading_portfolio_approval_policy_v1','status'=>'reference_only','policy_id'=>'policy-1','policy_version'=>'v1','approval_scope'=>'entry_candidate_reference','portfolio_id'=>'portfolio-1','candidate_id'=>'candidate-1','requirements'=>['candidate_ready'=>true,'action_risk_evaluated'=>true,'reference_plan_materialized'=>true,'capital_risk_evaluated'=>true,'position_sizing_reference_available'=>true,'execution_readiness_reference_available'=>true,'portfolio_risk_evaluated'=>true,'portfolio_limits_passed'=>true,'authorization_required'=>true],'source'=>['type'=>'synthetic_test_fixture','identifier'=>'policy'],'approved_for_production'=>false,'approved_for_execution'=>false,'synthetic_test_only'=>true];}protected function base(array $over=[]):array{return array_replace_recursive(['decision_scope'=>'entry_evaluation','ticker'=>'BUMI','decision_at'=>'2026-07-01T10:00:00+07:00','action_candidate'=>$this->candidate(),'risk'=>$this->risk(),'trade_plan'=>$this->plan(),'portfolio_approval_policy'=>$this->policy()],$over);}protected function auth(string $fp,array $over=[]):array{return array_replace_recursive(['schema_version'=>'trading_portfolio_authorization_v1','status'=>'reference_only','authorization_id'=>'auth-1','authorization_type'=>'reference_approval','authorization_decision'=>'approve_reference','approval_scope'=>'entry_candidate_reference','portfolio_id'=>'portfolio-1','candidate_id'=>'candidate-1','policy_id'=>'policy-1','policy_version'=>'v1','decision_fingerprint'=>$fp,'issued_by'=>['type'=>'synthetic_test_fixture','identifier'=>'issuer'],'issued_at'=>'2026-07-01T09:00:00+07:00','expires_at'=>'2026-07-01T11:00:00+07:00','production_authority'=>false,'execution_authority'=>false,'synthetic_test_only'=>true],$over);}public function test_unavailable_incomplete_and_eligible_without_auth():void{$svc=$this->svc();$this->assertSame('unavailable',$svc->evaluate($this->base(['action_candidate'=>null]))['status']);$this->assertSame('unavailable',$svc->evaluate($this->base(['risk'=>$this->risk('unavailable')]))['status']);$this->assertSame('blocked',$svc->evaluate($this->base(['risk'=>$this->risk('limit_exceeded_reference')]))['status']);$r=$svc->evaluate($this->base());$this->assertSame('eligible_for_reference_approval',$r['status']);$this->assertFalse($r['approval_result']['reference_approved']);}
public function test_approved_denied_expired_and_limit_override():void{$svc=$this->svc();$base=$this->base();$fp=$svc->approvalContextFingerprint($base+['policy_evaluation'=>(new \App\Services\Trading\PortfolioApprovalPolicyService())->evaluate($base),'portfolio_risk'=>$base['risk']['portfolio_risk']]);$approved=$svc->evaluate($base+['portfolio_authorization'=>$this->auth($fp)]);$this->assertSame('approved_reference',$approved['status']);$this->assertTrue($approved['approval_result']['reference_approved']);$this->assertFalse($approved['approval_result']['production_approved']);$this->assertFalse($approved['approval_result']['execution_approved']);$this->assertNull($approved['approved_action']);$this->assertNull($approved['approved_quantity']);$denied=$svc->evaluate($base+['portfolio_authorization'=>$this->auth($fp,['authorization_decision'=>'deny_reference'])]);$this->assertSame('denied_reference',$denied['status']);$expired=$svc->evaluate($base+['portfolio_authorization'=>$this->auth($fp,['expires_at'=>'2026-07-01T09:30:00+07:00'])]);$this->assertSame('blocked',$expired['status']);$limit=$svc->evaluate($this->base(['risk'=>$this->risk('limit_exceeded_reference'),'portfolio_authorization'=>$this->auth($fp)]));$this->assertSame('blocked',$limit['status']);$this->assertFalse($limit['approval_result']['reference_approved']);}
public function test_deterministic_and_validator():void{$svc=$this->svc();$a=$svc->evaluate($this->base());$b=$svc->evaluate($this->base());$this->assertSame($a,$b);$a['approved_quantity']=100;$this->expectException(\InvalidArgumentException::class);$svc->validateApproval($a);}}
